const familyProfile = $('Get Family Profile').first().json;

// Compute upcoming Monday (week_of)
const now = new Date();
const day = now.getDay();
const daysUntilMonday = day === 0 ? 1 : (8 - day) % 7 || 7;
const monday = new Date(now);
monday.setDate(now.getDate() + daysUntilMonday);
const weekOf = monday.toISOString().split('T')[0];

// Current date context for seasonal awareness
const currentMonth = now.toLocaleString('en-US', { month: 'long' });
const currentYear = now.getFullYear();
const hemisphere = 'northern';

// Proposal count driven by family config
const targetApprovals = familyProfile.target_approvals || 2;
const numProposals = targetApprovals * 2;

// Last 3 weeks of meal history titles
const history = $input.all().map(i => i.json);
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 21);
const recentTitles = history
  .filter(h => new Date(h.week_of) >= cutoff)
  .map(h => h.title)
  .join('\n') || 'None yet';

return [{ json: {
  week_of: weekOf,
  current_month: currentMonth,
  current_year: currentYear,
  hemisphere,
  family_profile: familyProfile,
  recent_titles: recentTitles,
  target_approvals: targetApprovals,
  num_proposals: numProposals
} }];

const bundleCtx = $('Bundle Context').first().json;
const weekOf = bundleCtx.week_of;
const targetApprovals = bundleCtx.target_approvals || 2;
const spoonacularMap = $('Format Spoonacular Results').first().json.spoonacular_map;

const parsed = $input.first().json.output;
const candidates = parsed?.candidates;

if (!candidates || !Array.isArray(candidates)) {
  throw new Error('Missing candidates array. Got: ' + JSON.stringify($input.first().json).substring(0, 300));
}

function normalize(name) {
  return name.toLowerCase()
    .replace(/^(fresh|dried|ground|chopped|diced|minced|sliced)\s+/i, '')
    .replace(/s$/, '').trim();
}

const sets = candidates.map((c, i) => ({
  idx: i + 1, title: c.title,
  ingredients: new Set(c.key_ingredients.map(ing => normalize(ing.name)))
}));

function combos(arr, k) {
  if (k === 0) return [[]];
  if (arr.length < k) return [];
  const [first, ...rest] = arr;
  return [...combos(rest, k-1).map(c => [first, ...c]), ...combos(rest, k)];
}

// Use target_approvals as the subset size for overlap scoring
const scored = combos(sets, targetApprovals).map(group => {
  const shared = [...group[0].ingredients].filter(i =>
    group.slice(1).every(m => m.ingredients.has(i))
  );
  return { indices: group.map(t => t.idx), shared_count: shared.length, shared };
}).sort((a, b) => b.shared_count - a.shared_count).slice(0, 3);

// Enrich candidates with Spoonacular URLs + nutrition
const enrichedCandidates = candidates.map(c => {
  const spData = (spoonacularMap || {})[String(c.spoonacular_id)] || {};
  return {
    ...c,
    source_url: spData.source_url || null,
    image_url: spData.image_url || null,
    nutrition: spData.nutrition || null
  };
});

return [{ json: { week_of: weekOf, target_approvals: targetApprovals, candidates: enrichedCandidates, top_combos: scored } }];

const { candidates, week_of } = $input.first().json;
return candidates.map(c => ({
  json: {
    week_of,
    title: c.title,
    description: c.description,
    cuisine: c.cuisine || null,
    protein: c.protein || null,
    active_time_min: c.active_time_min || null,
    key_ingredients: c.key_ingredients,
    source_url: c.source_url || null,
    image_url: c.image_url || null,
    nutrition: c.nutrition || null,
    status: 'pending'
  }
}));

const { target_approvals: TARGET_APPROVALS, top_combos: topCombos } = $('Parse + Score Overlap').first().json;
const rows = $input.all().map(i => i.json);
const weekOf = rows[0].week_of;

const TRUNCATE_LEN = 20;
const truncate = (s, n) => s.length > n ? s.slice(0, n) + '…' : s;

const mealList = rows.map((r, idx) => {
  const n = r.nutrition;
  const macroStr = (n?.calories && n?.protein_g)
    ? ` | ${n.calories} cal · ${n.protein_g}g protein`
    : '';
  return `${idx + 1}. *${r.title}* — ${r.description}${macroStr}`;
}).join('\n\n');

const comboHints = topCombos.map(c =>
  `  • ${c.indices.join(' + ')} → shares ${c.shared_count} ingredient${c.shared_count !== 1 ? 's' : ''}`
).join('\n');

const text = `🍽️ Meal ideas — week of ${weekOf}\n\n${mealList}\n\n🛒 Budget combos (most shared ingredients):\n${comboHints}\n\nTap to approve/deny. Either parent can decide. First tap wins.\nTarget: ${TARGET_APPROVALS} approvals.`;

const inlineKeyboard = rows.map((r, idx) => {
  const label = `${idx + 1}. ${truncate(r.title, TRUNCATE_LEN)}`;
  const buttons = [
    {text: `${label} ✅`, callback_data: `approve:${r.id}`},
    {text: `❌`, callback_data: `deny:${r.id}`}
  ];
  if (r.source_url) {
    buttons.push({text: `🔗`, url: r.source_url});
  }
  return buttons;
});

const mediaGroup = rows
  .filter(r => r.image_url)
  .map((r, idx) => ({
    type: 'photo',
    media: r.image_url,
    caption: `${idx + 1}. ${r.title}`
  }));

return [{ json: { text, chat_id: $env.TELEGRAM_CHAT_ID, reply_markup: {inline_keyboard: inlineKeyboard}, media_group: mediaGroup } }];

