const bundleCtx = $('Bundle Context').first().json;
const results = $input.first().json.results || [];

if (results.length === 0) {
  throw new Error('Spoonacular returned no results. Check API key and query params.');
}

function getNutrient(nutrients, name) {
  const n = (nutrients || []).find(n => n.name === name);
  return n ? Math.round(n.amount) : null;
}

// Build lookup map id -> {image_url, source_url, nutrition}
const spoonacularMap = {};
for (const r of results) {
  const nutrients = r.nutrition?.nutrients || [];
  spoonacularMap[String(r.id)] = {
    image_url: `https://img.spoonacular.com/recipes/${r.id}-480x360.jpg`,
    source_url: r.sourceUrl || null,
    likes: r.aggregateLikes || 0,
    score: Math.round(r.spoonacularScore || 0),
    nutrition: {
      calories: getNutrient(nutrients, 'Calories'),
      protein_g: getNutrient(nutrients, 'Protein'),
      carbs_g: getNutrient(nutrients, 'Carbohydrates'),
      fat_g: getNutrient(nutrients, 'Fat'),
      fiber_g: getNutrient(nutrients, 'Fiber')
    }
  };
}

// Build numbered text list for Claude — include macros so it can make protein-aware picks
const recipeList = results.map((r, i) => {
  const sp = spoonacularMap[String(r.id)];
  const cal = sp.nutrition.calories;
  const pro = sp.nutrition.protein_g;
  const macroStr = (cal && pro) ? `, ${cal} cal, ${pro}g protein` : '';
  return `${i + 1}. [ID:${r.id}] "${r.title}" (~${r.readyInMinutes}min, ${r.aggregateLikes || 0} likes, score: ${sp.score}${macroStr})`;
}).join('\n');

return [{
  json: {
    ...bundleCtx,
    spoonacular_recipes: recipeList,
    spoonacular_map: spoonacularMap
  }
}];

const proposals = $input.all().map(i => i.json).filter(p => p.id);

// Only consider proposals from the most recent week_of
const weeks = [...new Set(proposals.map(p => p.week_of))].sort().reverse();
const latestWeek = weeks[0];
const current = latestWeek
  ? proposals.filter(p => p.week_of === latestWeek)
  : [];

const active = current.filter(p => ['pending', 'approved'].includes(p.status));
return [{ json: { hasActive: active.length > 0, activeCount: active.length, week_of: latestWeek || null } }];
